## Background

End-to-end tests verify the full output rendering pipeline works correctly in real terminal conditions and degrades gracefully in CI environments.

## Test Scenarios

### 1. Terminal Output Tests (tests/e2e/terminal_output.rs)

```rust
#[test]
fn e2e_denial_displays_rich_box_in_terminal() {
    log::info\!("=== E2E: Testing rich denial output in terminal ===");

    // Spawn dcg in PTY to simulate real terminal
    let mut pty = PtySession::new("dcg").unwrap();
    pty.send_line("hook --hook-type pre_tool_use --input '{ \"tool_name\": \"Bash\", \"tool_input\": { \"command\": \"rm -rf /\" } }'");

    let output = pty.read_until_prompt(Duration::from_secs(5));
    log::debug\!("Terminal output captured:\n{}", output);

    // Verify box drawing characters present
    assert\!(output.contains("╭") || output.contains("+"), "Box top border missing");
    assert\!(output.contains("╰") || output.contains("+"), "Box bottom border missing");
    assert\!(output.contains("BLOCKED"), "BLOCKED header missing");

    log::info\!("=== E2E: Terminal output test PASSED ===");
}

#[test]
fn e2e_scan_displays_table_with_colors() {
    log::info\!("=== E2E: Testing scan table output ===");

    // Create test files with known issues
    let temp_dir = TempDir::new().unwrap();
    fs::write(temp_dir.path().join("Dockerfile"), "RUN rm -rf /").unwrap();

    let output = Command::new("dcg")
        .args(["scan", temp_dir.path().to_str().unwrap()])
        .output()
        .unwrap();

    let stdout = String::from_utf8_lossy(&output.stdout);
    log::debug\!("Scan output:\n{}", stdout);

    assert\!(stdout.contains("Dockerfile"), "File name missing from table");
    assert\!(stdout.contains("HIGH") || stdout.contains("CRITICAL"), "Severity missing");

